import React, { useEffect, useState } from 'react';
import { getMarketData } from '../services/marketService';

const LiveTicker = () => {
    const [data, setData] = useState([]);

    useEffect(() => {
        const fetchData = async () => {
            const result = await getMarketData();
            setData(result);
        };
        fetchData();
        // DİKKAT: Ücretsiz API hesaplarında genelde "Aylık 100 Sorgu" hakkı olur. 
        // Hakkımız 10 dakikada bitmesin diye süreyi 5 saniyeden 60 saniyeye (60000ms) çıkardım.
        const interval = setInterval(fetchData, 60000);
        return () => clearInterval(interval);
    }, []);

    // Sonsuz kayma efekti için veriyi kopyalıyoruz
    const tickerItems = [...data, ...data, ...data, ...data];

    return (
        <div className="live-ticker-band">
            <div className="ticker-fade-left"></div>
            <div className="ticker-track">
                {tickerItems.map((item, index) => (
                    <div key={index} className="ticker-item">
                        <span className="ticker-symbol">{item.symbol}</span>
                        <span className="ticker-price">{item.price}</span>
                        <span className={`ticker-trend ${item.trend}`}>
                           {item.trend === 'up' ? '▲' : '▼'}
                        </span>
                    </div>
                ))}
            </div>
            <div className="ticker-fade-right"></div>
        </div>
    );
};

export default LiveTicker;
